/* ─── Platform Tier Card ──────────────────────────────────────────────────── */

function TierCard({ tier, isAnnual, isCurrentPlan, onSubscribe, loading, mobile }) {
  const isPro = tier.key === 'pro' || tier.popular;
  const price = isAnnual ? (tier.annual ?? tier.price_annual ?? 0) : (tier.monthly ?? tier.price_monthly ?? 0);
  const isFree = price === 0;

  const borderColor = isCurrentPlan
    ? C.purple
    : isPro
      ? C.blue
      : C.border;

  const cardCls = mobile ? s.tierCardMobile : s.tierCardDesktop;

  return (
    <div
      className={`${cardCls} ${isPro ? s.tierCardPro : ''}`}
      style={{
        border: `1px solid ${borderColor}`,
        boxShadow: isPro ? `0 0 24px ${C.blue}18` : undefined,
      }}
    >
      {isPro && !isCurrentPlan && (
        <div className={s.cardBadge} style={{ background: C.blue, color: C.bg }}>
          MOST POPULAR
        </div>
      )}

      {tier.bestForLearning && !isCurrentPlan && !isPro && (
        <div className={s.cardBadge} style={{ background: C.green, color: C.bg }}>
          BEST FOR LEARNING
        </div>
      )}

      {isCurrentPlan && (
        <div className={s.cardBadge} style={{ background: C.purple, color: '#fff' }}>
          CURRENT PLAN
        </div>
      )}

      <div className={s.tierLabel}>{tier.label}</div>
      {tier.tagline && <div className={s.tierTagline}>{tier.tagline}</div>}

      <div className={s.tierPriceWrap}>
        <span className={s.tierPrice}>${price}</span>
        {!isFree && <span className={s.tierPeriod}>/mo</span>}
        {isFree && <span className={s.tierPeriod}> forever</span>}
        {isAnnual && !isFree && (
          <div className={s.tierSavings}>
            billed ${price * 12}/yr &mdash; save {Math.round((1 - price / (tier.monthly ?? tier.price_monthly ?? price)) * 100)}%
          </div>
        )}
      </div>

      <div className={s.featureList}>
        {(tier.features || []).map((f, i) => (
          <div key={i} className={`${s.featureItem} ${f.included ? s.featureIncluded : s.featureExcluded}`}>
            {f.included ? <CheckIcon /> : <DashIcon />}
            {f.text}
          </div>
        ))}
      </div>

      {isCurrentPlan ? (
        <button disabled className={s.cardBtnDisabled} style={{ border: `1px solid ${C.purple}`, background: 'transparent', color: C.purple }}>
          Current Plan
        </button>
      ) : (
        <button
          onClick={() => onSubscribe(tier.key)}
          disabled={loading}
          className={s.cardBtn}
          style={{
            background: isFree ? C.surface2 : isPro ? C.blue : C.surface2,
            color: isPro ? C.bg : C.textPrimary,
            cursor: loading ? 'wait' : 'pointer',
            opacity: loading ? 0.6 : 1,
          }}
        >
          {isFree ? 'Get Started Free' : 'Subscribe'}
        </button>
      )}
    </div>
  );
}

